INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (4, "2019/07/31 12:00:00", 4, 110501, 0.0, "2030/12/17 14:59:59", 24015, "カオリ（サマー）", 0.0, 10021, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 24, 0.0, 1);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (4, "2019/07/31 12:00:00", 1, 110501, 0.0, "2030/12/17 14:59:59", 24016, "カオリ（サマー）", 0.0, 10021, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 24, 4.0, 2);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (4, "2019/07/31 12:00:00", 4, 110501, 0.0, "2030/12/17 14:59:59", 24017, "カオリ（サマー）", 0.0, 10021, "マジムンだらけで目が回るさ～！\nふらふらさ～！", 24, 0.0, 3);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (1, "2019/07/31 12:00:00", 2, 110501, 0.0, "2030/12/17 14:59:59", 24018, "カオリ（サマー）", 0.0, 10021, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 24, 5.2, 4);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (5, "2019/07/31 12:00:00", 6, 110501, 0.0, "2030/12/17 14:59:59", 24019, "カオリ（サマー）", 0.0, 10021, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 24, 4.2, 5);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (2, "2019/07/31 12:00:00", 2, 110501, 0.0, "2030/12/17 14:59:59", 24020, "カオリ（サマー）", 0.0, 10021, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 24, 0.0, 6);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (1, "2019/07/31 12:00:00", 6, 110501, 0.0, "2030/12/17 14:59:59", 24021, "カオリ（サマー）", 0.0, 10021, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 24, 6.4, 7);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (2, "2019/07/31 12:00:00", 2, 110501, 0.0, "2030/12/17 14:59:59", 24022, "カオリ（サマー）", 0.0, 10021, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 24, 0.0, 8);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (6, "2019/07/31 12:00:00", 3, 110501, 0.0, "2030/12/17 14:59:59", 24023, "カオリ（サマー）", 0.0, 10021, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 24, 10.08, 9);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (1, "2019/07/31 12:00:00", 2, 110501, 0.0, "2030/12/17 14:59:59", 24024, "カオリ（サマー）", 0.0, 10021, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 24, 5.0, 10);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (2, "2019/07/31 12:00:00", 2, 110501, 0.0, "2030/12/17 14:59:59", 24025, "カオリ（サマー）", 0.0, 10021, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 24, 0.0, 11);
